use std::collections::HashMap;

#[derive(Debug, Clone)]
pub struct Registry<T> {
    entries: HashMap<String, T>,
}

impl<T: Clone> Registry<T> {
    pub fn new() -> Self {
        Self { entries: HashMap::new() }
    }

    /// Register a value by ID.
    pub fn register(&mut self, id: impl Into<String>, value: T) {
        self.entries.insert(id.into(), value);
    }

    pub fn get(&self, id: &str) -> Option<&T> {
        self.entries.get(id)
    }
}

previews.Python:
from dataclasses import dataclass, field
from typing import Optional

@dataclass
class Extension:
    id: str
    name: str
    version: str
    installed: bool = False
    tags: list[str] = field(default_factory=list)

    def matches(self, query: str) -> bool:
        """Return True if query matches name or any tag."""
        q = query.lower()
        return q in self.name.lower() or any(q in t for t in self.tags)

    def install(self) -> None:
        if self.installed:
            raise ValueError(f"{self.name!r} is already installed")
        self.installed = True

